 1→package com.taskflow.security;
 2→
 3→import io.jsonwebtoken.Jwts;
 4→import io.jsonwebtoken.security.Keys;
 5→import org.springframework.beans.factory.annotation.Value;
 6→import org.springframework.stereotype.Component;
 7→
 8→import javax.crypto.SecretKey;
 9→import java.nio.charset.StandardCharsets;
10→import java.util.Date;
11→
12→@Component
13→public class JwtTokenProvider {
14→
15→    private final SecretKey key;
16→    private final long expirationMs;
17→
18→    public JwtTokenProvider(
19→            @Value("${app.jwt.secret}") String secret,
20→            @Value("${app.jwt.expiration}") long expirationMs) {
21→        this.key = Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8));
22→        this.expirationMs = expirationMs;
23→    }
24→
25→    public String generateToken(Long userId) {
26→        Date now = new Date();
27→        Date expiryDate = new Date(now.getTime() + expirationMs);
28→
29→        return Jwts.builder()
30→                .subject(String.valueOf(userId))
31→                .issuedAt(now)
32→                .expiration(expiryDate)
33→                .signWith(key)
34→                .compact();
35→    }
36→
37→    public Long getUserIdFromToken(String token) {
38→        String subject = Jwts.parser()
39→                .verifyWith(key)
40→                .build()
41→                .parseSignedClaims(token)
42→                .getPayload()
43→                .getSubject();
44→        return Long.parseLong(subject);
45→    }
46→
47→    public boolean validateToken(String token) {
48→        if (token == null || token.isEmpty()) {
49→            return false;
50→        }
51→        try {
52→            Jwts.parser()
53→                    .verifyWith(key)
54→                    .build()
55→                    .parseSignedClaims(token);
56→            return true;
57→        } catch (Exception e) {
58→            return false;
59→        }
60→    }
61→}
