 1→package com.taskflow.security;
 2→
 3→import jakarta.servlet.FilterChain;
 4→import jakarta.servlet.ServletException;
 5→import jakarta.servlet.http.HttpServletRequest;
 6→import jakarta.servlet.http.HttpServletResponse;
 7→import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
 8→import org.springframework.security.core.context.SecurityContextHolder;
 9→import org.springframework.stereotype.Component;
10→import org.springframework.web.filter.OncePerRequestFilter;
11→
12→import java.io.IOException;
13→import java.util.Collections;
14→
15→@Component
16→public class JwtAuthFilter extends OncePerRequestFilter {
17→
18→    private final JwtTokenProvider tokenProvider;
19→
20→    public JwtAuthFilter(JwtTokenProvider tokenProvider) {
21→        this.tokenProvider = tokenProvider;
22→    }
23→
24→    @Override
25→    protected void doFilterInternal(HttpServletRequest request,
26→                                     HttpServletResponse response,
27→                                     FilterChain filterChain)
28→            throws ServletException, IOException {
29→
30→        String token = extractToken(request);
31→
32→        if (token != null && tokenProvider.validateToken(token)) {
33→            Long userId = tokenProvider.getUserIdFromToken(token);
34→            UsernamePasswordAuthenticationToken authentication =
35→                    new UsernamePasswordAuthenticationToken(userId, null, Collections.emptyList());
36→            SecurityContextHolder.getContext().setAuthentication(authentication);
37→        }
38→
39→        filterChain.doFilter(request, response);
40→    }
41→
42→    private String extractToken(HttpServletRequest request) {
43→        String header = request.getHeader("Authorization");
44→        if (header != null && header.startsWith("Bearer ")) {
45→            String token = header.substring(7);
46→            return token.isEmpty() ? null : token;
47→        }
48→        return null;
49→    }
50→}
