 11→/**
 12→ * Unit tests for JwtTokenProvider.
 13→ *
 14→ * No Spring context needed — instantiate directly with constructor args.
 15→ * Expected constructor: JwtTokenProvider(String secret, long expirationMs)
 16→ *
 17→ * Covers:
 18→ * - Token generation: contains userId claim, is non-empty
 19→ * - Token parsing: extract userId from valid token
 20→ * - Token validation: valid token returns true
 21→ * - Expired token detection
 22→ * - Malformed/invalid token handling
 23→ * - Null/empty token handling
 24→ */
 25→@DisplayName("JwtTokenProvider Unit Tests")
 26→class JwtTokenProviderTest {
 27→
 28→    private static final String SECRET = "test-jwt-secret-key-must-be-at-least-256-bits-long-for-HS256";
 29→    private static final long EXPIRATION_MS = 86400000L; // 24 hours
 30→    private static final long SHORT_EXPIRATION_MS = 1L; // 1ms for expiry tests
 31→
 32→    private JwtTokenProvider tokenProvider;
 33→
 34→    @BeforeEach
 35→    void setUp() {
 36→        tokenProvider = new JwtTokenProvider(SECRET, EXPIRATION_MS);
 37→    }
 38→
 39→    @Nested
 40→    @DisplayName("Token Generation")
 41→    class TokenGeneration {
 42→
 43→        @Test
 44→        @DisplayName("should generate non-empty token for valid userId")
 45→        void shouldGenerateNonEmptyTokenForValidUserId() {
 46→            String token = tokenProvider.generateToken(1L);
 47→
 48→            assertThat(token).isNotNull().isNotEmpty();
 49→        }
 50→
 51→        @Test
 52→        @DisplayName("should generate different tokens for different userIds")
 53→        void shouldGenerateDifferentTokensForDifferentUserIds() {
 54→            String token1 = tokenProvider.generateToken(1L);
 55→            String token2 = tokenProvider.generateToken(2L);
 56→
 57→            assertThat(token1).isNotEqualTo(token2);
 58→        }
 59→
 60→        @Test
 61→        @DisplayName("should generate token that contains three parts separated by dots")
 62→        void shouldGenerateTokenWithThreePartsJwtFormat() {
 63→            String token = tokenProvider.generateToken(1L);
 64→
 65→            String[] parts = token.split("\\.");
 66→            assertThat(parts).hasSize(3); // header.payload.signature
 67→        }
 68→    }
 69→
 70→    @Nested
 71→    @DisplayName("Token Parsing")
 72→    class TokenParsing {
 73→
 74→        @Test
 75→        @DisplayName("should extract userId from valid token")
 76→        void shouldExtractUserIdFromValidToken() {
 77→            Long userId = 42L;
 78→            String token = tokenProvider.generateToken(userId);
 79→
 80→            Long extractedId = tokenProvider.getUserIdFromToken(token);
 81→
 82→            assertThat(extractedId).isEqualTo(userId);
 83→        }
 84→
 85→        @Test
 86→        @DisplayName("should extract correct userId for different users")
 87→        void shouldExtractCorrectUserIdForDifferentUsers() {
 88→            String token1 = tokenProvider.generateToken(1L);
 89→            String token2 = tokenProvider.generateToken(999L);
 90→
 91→            assertThat(tokenProvider.getUserIdFromToken(token1)).isEqualTo(1L);
 92→            assertThat(tokenProvider.getUserIdFromToken(token2)).isEqualTo(999L);
 93→        }
 94→    }
 95→
 96→    @Nested
 97→    @DisplayName("Token Validation")
 98→    class TokenValidation {
 99→
100→        @Test
101→        @DisplayName("should return true for valid non-expired token")
102→        void shouldReturnTrueForValidNonExpiredToken() {
103→            String token = tokenProvider.generateToken(1L);
104→
105→            boolean isValid = tokenProvider.validateToken(token);
106→
107→            assertThat(isValid).isTrue();
108→        }
109→
110→        @Test
111→        @DisplayName("should return false for expired token")
112→        void shouldReturnFalseForExpiredToken() throws InterruptedException {
113→            JwtTokenProvider shortLivedProvider = new JwtTokenProvider(SECRET, SHORT_EXPIRATION_MS);
114→            String token = shortLivedProvider.generateToken(1L);
115→
116→            // Wait for token to expire
117→            Thread.sleep(50);
118→
119→            boolean isValid = shortLivedProvider.validateToken(token);
120→
121→            assertThat(isValid).isFalse();
122→        }
123→
124→        @Test
125→        @DisplayName("should return false for malformed token")
126→        void shouldReturnFalseForMalformedToken() {
127→            boolean isValid = tokenProvider.validateToken("not.a.valid.jwt.token");
128→
129→            assertThat(isValid).isFalse();
130→        }
131→
132→        @Test
133→        @DisplayName("should return false for empty token")
134→        void shouldReturnFalseForEmptyToken() {
135→            boolean isValid = tokenProvider.validateToken("");
136→
137→            assertThat(isValid).isFalse();
138→        }
139→
140→        @Test
141→        @DisplayName("should return false for null token")
142→        void shouldReturnFalseForNullToken() {
143→            boolean isValid = tokenProvider.validateToken(null);
144→
145→            assertThat(isValid).isFalse();
146→        }
147→
148→        @Test
