150→        void shouldReturnFalseForTamperedToken() {
151→            String token = tokenProvider.generateToken(1L);
152→            // Tamper with the last character of the signature
153→            String tampered = token.substring(0, token.length() - 1) + (token.endsWith("A") ? "B" : "A");
154→
155→            boolean isValid = tokenProvider.validateToken(tampered);
156→
157→            assertThat(isValid).isFalse();
158→        }
159→
160→        @Test
