167→            String token = otherProvider.generateToken(1L);
168→
169→            boolean isValid = tokenProvider.validateToken(token);
170→
171→            assertThat(isValid).isFalse();
172→        }
173→
174→        @Test
175→        @DisplayName("should return false for random string")
176→        void shouldReturnFalseForRandomString() {
