 57→
 58→        @Test
 59→        @DisplayName("should set authentication in SecurityContext when valid Bearer token is provided")
 60→        void shouldSetAuthenticationWhenValidBearerToken() throws ServletException, IOException {
 61→            String token = "valid.jwt.token";
